function countNegatives(grid) {
    const m = grid.length, n = grid[0].length;
    let count = 0, i = 0, j = n - 1;
    while (i < m && j >= 0) {
        if (grid[i][j] < 0) {
            count += j + 1;
            i++;
        } else {
            j--;
        }
    }
    return count;
}
